-- ═══════════════════════════════════════════════════════════════════════════════
-- Mega Man X2.lua — game module for the Archipelago BizHawk connector.
--                   Mega Man X2 (SNES)
--
-- STATUS: COMMUNITY world. location DETECTION + goal are REAL and SOURCE-DERIVED
-- from the official apworld worlds/mmx2 (Client.py game_watcher + Locations.py +
-- Levels.py, TheLX5/Archipelago @ branch `mmx2`). The 135-entry location table was
-- GENERATED by JOINING Locations.all_locations (name → AP id) with
-- Levels.location_id_to_level_id (name → [stage, internal_id, data_bit]) using the
-- real Names.LocationName module — not hand-copied — so every (AP id →
-- internal_id/data_bit) pair is exact. Mock-verified through MoonSharp against
-- synthetic WRAM/CARTROM. Loads crash-free on any ROM; self-disables on a non-AP
-- cartridge.
--
-- SOURCE: https://github.com/TheLX5/Archipelago  (branch `mmx2`, worlds/mmx2)
--         game string "Mega Man X2", patch_suffix ".apmmx2", items_handling 0b111.
--
-- MEMORY MODEL (SNI → BizHawk)  — same SNIClient bridge family as Mega Man X
-- ──────────────────────────────────────────────────────────────────────────
--   The mmx2 client is an SNIClient. Its SNI addresses translate to BizHawk SNES
--   memory domains:
--     SNI WRAM_START(0xF50000)+off → domain "WRAM",    offset off (= $7E0000+off)
--     SNI ROM_START(0x000000)+off  → domain "CARTROM", offset off (raw ROM file
--                                    offset; LoROM. Fallbacks "ROM"/"System Bus")
--   Note: the mmx2 base patch fills a 1.5 MB (0x180000) ROM and the client's
--   settings live high in CARTROM at 0x17FFExx — confirmed by Rom.py's writes.
--   The client reads several contiguous RAM blocks; this module reads the same:
--     MMX2_RAM = WRAM+0x1F800 (the AP scratch/data block base). Sub-fields:
--       • game_state      = WRAM 0x000D0  (1 byte)   game_state_data[0]
--       • menu_state      = WRAM 0x000D1  (1 byte)
--       • gameplay_state  = WRAM 0x000D2  (1 byte)
--       • validation word = WRAM 0x1F811  (u16 LE)   == 0xDEAD when patched+running
--       • defeated_bosses = WRAM 0x1F8A0  (0x20 idx)  index by data_bit
--       • cleared_levels  = WRAM 0x1F880  (0x20 idx)  index by data_bit
--       • heart_tanks     = WRAM 0x1F840  (1 byte)    MASK
--       • upgrades        = WRAM 0x1F841  (1 byte)    MASK (upgrades AND sub-tanks)
--       • shoryuken       = WRAM 0x1F842  (1 byte)    != 0
--       • sigma_access    = WRAM 0x1F846  (1 byte)    != 0
--       • collected_pickups = WRAM 0x1F8C0 (0x4E idx) index by data_bit
--     game_settings (pickupsanity gate) = CARTROM 0x17FFE7 (per-seed-baked byte)
--   IDENTITY / VALIDATION (two gates, both mirrored from Client.py):
--     1) ROM header title at CARTROM 0x7FC0 begins with "MMX2" (validate_rom:
--        rom_name[:4] == b"MMX2"). This is baked by the AP basepatch.
--     2) The live AP-validation word (WRAM 0x1F811/0x1F812, little-endian) ==
--        0xDEAD (game_watcher's per-frame "ROM properly validated" check). Only a
--        patched-and-running ROM sets this.
--
-- HOW MMX2 CHECKS WORK (mirrors Client.py game_watcher; per-location internal_id)
--   Each location carries {internal_id, data_bit}:
--     0x000 Boss clear  : defeated_bosses[data_bit] != 0          (INDEX, not mask)
--     0x001 Maverick    : cleared_levels[data_bit]  != 0          (INDEX)
--     0x002 Heart Tank  : heart_tanks & data_bit != 0             (MASK on one byte)
--     0x003 Upgrade     : upgrades    & data_bit != 0             (MASK)
--     0x004 Sub Tank    : upgrades    & data_bit != 0             (MASK; same byte as 003)
--     0x005 Shoryuken   : shoryuken    != 0                        (data_bit unused)
--     0x006 Sigma access: sigma_access != 0                        (data_bit unused)
--     0x007 Intro clear : game_state==0x02 AND menu_state==0x00 AND gameplay_state==0x01
--     0x020 Pickup      : gated on pickupsanity (CARTROM 0x17FFE7);
--                          collected_pickups[data_bit] != 0  (INDEX)
--
-- WHAT THIS DOES
--   • poll(): the game_watcher location scan above → AP location ids, gated to the
--     slot's server location set and to the in-game state. game_watcher bails when
--     game_state[0] == 0 (title / no save) and reports checks while game_state != 0
--     with validation == 0xDEAD. We require the live 0xDEAD word plus game_state != 0.
--   • is_goal_complete(): Sigma defeated — the victory location ("Defeated Sigma",
--     AP id 12454933) is internal_id 0x000, data_bit 0x17 → defeated_bosses[0x17]
--     (WRAM 0x1F8B7) != 0. The apworld places the locked Victory item there;
--     defeating Sigma is the goal.
--   • receive_item(): NO-OP (documented). items_handling = 0b111 (FULL remote) —
--     the mmx2 client owns ALL item delivery via an intricate, heavily-state-gated
--     set of WRAM writes (weapon/upgrade/sub-tank/heart-tank/enhancement/boss-
--     access arrays, a recv-index handshake at MMX2_RAM+0x00, an SFX strobe, a
--     per-item queue that waits on menu/gameplay/pause/can-move/screen-brightness/
--     ride-armor states, an arsenal save/load round-trip through AP data-storage,
--     plus EnergyLink/DeathLink/HP-trade). That path is the one piece that needs
--     in-emulator verification before it is wired, so it is left out rather than
--     shipped unverified (a wrong write would corrupt the save / desync recv-index).
--     Checks + goal above are fully functional regardless of this gap.
--
-- MODULE CONTRACT (called by bizhawk_ap_connector.lua)
--   M.init(ctx) / M.poll() -> {ids} / M.is_goal_complete() -> bool /
--   M.receive_item(item_id, meta)
-- ═══════════════════════════════════════════════════════════════════════════════

local M = {}
M.name = "Mega Man X2"

local ADDRESSES_VERIFIED = true   -- table generated from worlds/mmx2 source

-- ── Memory domains ────────────────────────────────────────────────────────────
local WRAM    = "WRAM"
local CARTROM = "CARTROM"     -- SNES cartridge ROM in BizHawk; fallbacks below

-- ── Addresses / constants (worlds/mmx2/Client.py module top) ──────────────────
-- Expressed as BizHawk-domain offsets (already net of WRAM_START / ROM_START).
-- MMX2_RAM = WRAM_START + 0x1F800.
local MMX2_RAM_OFF      = 0x1F800

local GAME_STATE_OFF    = 0x000D0     -- WRAM: game_state_data[0]
local MENU_STATE_OFF    = 0x000D1     -- WRAM: menu_state
local GAMEPLAY_STATE_OFF= 0x000D2     -- WRAM: gameplay_state

-- MMX2_RAM sub-fields (offsets RELATIVE to MMX2_RAM_OFF).
local R_VALIDATION      = 0x00011     -- u16 LE; == 0xDEAD when patched+running
local R_HEART_TANKS     = 0x00040     -- u8 mask: collected heart-tank flags
local R_UPGRADES        = 0x00041     -- u8 mask: collected upgrade/sub-tank flags
local R_SHORYUKEN       = 0x00042     -- u8: != 0 once Shoryuken collected
local R_SIGMA_ACCESS    = 0x00046     -- u8: != 0 once Sigma access collected
local R_CLEARED_BASE    = 0x00080     -- cleared_levels[];   index by data_bit (0x20)
local R_BOSSES_BASE     = 0x000A0     -- defeated_bosses[];   index by data_bit (0x20)
local R_PICKUPS_BASE    = 0x000C0     -- collected_pickups[]; index by data_bit (0x4E)

-- Absolute WRAM offsets derived from MMX2_RAM_OFF (computed once).
local VALIDATION_OFF    = MMX2_RAM_OFF + R_VALIDATION     -- 0x1F811
local HEART_TANKS_OFF   = MMX2_RAM_OFF + R_HEART_TANKS    -- 0x1F840
local UPGRADES_OFF      = MMX2_RAM_OFF + R_UPGRADES       -- 0x1F841
local SHORYUKEN_OFF     = MMX2_RAM_OFF + R_SHORYUKEN      -- 0x1F842
local SIGMA_ACCESS_OFF  = MMX2_RAM_OFF + R_SIGMA_ACCESS   -- 0x1F846
local CLEARED_BASE_OFF  = MMX2_RAM_OFF + R_CLEARED_BASE   -- 0x1F880
local BOSSES_BASE_OFF   = MMX2_RAM_OFF + R_BOSSES_BASE    -- 0x1F8A0
local PICKUPS_BASE_OFF  = MMX2_RAM_OFF + R_PICKUPS_BASE   -- 0x1F8C0

-- game_settings / pickupsanity gate lives in CARTROM (per-seed-baked).
local PICKUPSANITY_OFF  = 0x17FFE7    -- CARTROM: MMX2_PICKUPSANITY_ACTIVE

local ROMHASH_OFF       = 0x7FC0      -- CARTROM: ROM-header title; first 4 = "MMX2"

-- Block sizes (match the client's snes_read lengths).
local LEN_BOSSES        = 0x20
local LEN_CLEARED       = 0x20
local LEN_PICKUPS       = 0x4E

-- Live validation word value.
local VALIDATION_OK     = 0xDEAD

-- Goal: Sigma defeated — boss clear index 0x17 (victory location "Defeated Sigma").
local GOAL_BOSS_INDEX   = 0x17

-- Check-type tags (Client.py game_watcher internal_id values).
local T_BOSS        = 0x000
local T_MAVERICK    = 0x001
local T_HEART_TANK  = 0x002
local T_UPGRADE     = 0x003
local T_SUB_TANK    = 0x004
local T_SHORYUKEN   = 0x005
local T_SIGMA       = 0x006
local T_INTRO       = 0x007
local T_PICKUP      = 0x020

