-- ── Internal state ────────────────────────────────────────────────────────────
local reported         = {}     -- ap_id -> true once returned from poll()
local server_locations = nil    -- set of ap_ids the server expects (nil = all)
local rom_ok           = nil    -- cached "MMX2" header result
local mem              = {}
local log_fn           = nil

-- ── Logging ───────────────────────────────────────────────────────────────────
local function log(msg)
  if log_fn then pcall(log_fn, "[mmx2] " .. tostring(msg)) end
end

-- ── Memory API (resolved at init; 2-arg domain form + current-domain fallback) ─
local function resolve_memory_api()
  if not memory then return false end
  mem.read_u8  = memory.read_u8     or memory.readbyte
  mem.read_u16 = memory.read_u16_le or memory.readword
  return mem.read_u8 ~= nil
end

local function rd(fn, addr, domain)
  if not fn then return nil end
  local ok, v = pcall(fn, addr, domain)
  if ok and type(v) == "number" then return v end
  ok, v = pcall(fn, addr)                       -- older API: current domain
  if ok and type(v) == "number" then return v end
  return nil
end

local function read_wram_u8(off)   return rd(mem.read_u8,  off, WRAM) end
local function read_wram_u16(off)  return rd(mem.read_u16, off, WRAM) end

-- CARTROM reads with "ROM" / "System Bus" domain-name fallbacks (cores vary;
-- the raw-file-offset CARTROM/ROM form is what every SNES BizHawk core exposes).
local function read_cartrom_u8(off)
  local ok, v = pcall(mem.read_u8, off, CARTROM)
  if ok and type(v) == "number" then return v end
  ok, v = pcall(mem.read_u8, off, "ROM")
  if ok and type(v) == "number" then return v end
  return nil
end

local function bit_and(a, b)
  -- 8/16-bit safe AND without the bit library (cores vary).
  local res, bitval = 0, 1
  while a > 0 and b > 0 do
    if a % 2 == 1 and b % 2 == 1 then res = res + bitval end
    a = math.floor(a / 2); b = math.floor(b / 2); bitval = bitval * 2
  end
  return res
end

-- ── ROM identity: the SNES header title starts with "MMX2" (validate_rom) ──────
local function rom_is_ap()
  if rom_ok ~= nil then return rom_ok end
  local sig = "MMX2"
  for i = 1, #sig do
    local b = read_cartrom_u8(ROMHASH_OFF + i - 1)
    if b == nil then return false end          -- not readable yet; retry next poll
    if b ~= string.byte(sig, i) then
      rom_ok = false
      log("non-MMX2 ROM (no 'MMX2' header) — detection idle, no reports")
      return false
    end
  end
  rom_ok = true
  log("MMX2 ROM verified ('MMX2' header title present)")
  return true
end

-- ── Multiworld context ────────────────────────────────────────────────────────
local function load_locations(ids)
  if type(ids) ~= "table" then return end
  server_locations = {}
  local n = 0
  for _, id in ipairs(ids) do
    local v = tonumber(id)
    if v then server_locations[v] = true; n = n + 1 end
  end
  log("server location set: " .. n .. " ids")
end

local function wanted(ap_id)
  if server_locations == nil then return true end   -- no set provided → report all
  return server_locations[ap_id] == true
end

-- ── Per-poll snapshots (read once per poll, matching game_watcher) ────────────
local snap = {}     -- the RAM blocks the client reads, refreshed each poll

local function read_region_wram(off, len)
  local t = {}
  for i = 0, len - 1 do t[i] = read_wram_u8(off + i) end
  return t
end

local function refresh_snapshot()
  snap.game_state     = read_wram_u8(GAME_STATE_OFF)
  snap.menu_state     = read_wram_u8(MENU_STATE_OFF)
  snap.gameplay_state = read_wram_u8(GAMEPLAY_STATE_OFF)
  snap.validation     = read_wram_u16(VALIDATION_OFF)
  -- index-based arrays (read the exact spans the client reads)
  snap.bosses  = read_region_wram(BOSSES_BASE_OFF,  LEN_BOSSES)
  snap.cleared = read_region_wram(CLEARED_BASE_OFF, LEN_CLEARED)
  snap.pickups = read_region_wram(PICKUPS_BASE_OFF, LEN_PICKUPS)
  -- single mask/flag bytes
  snap.heart_tanks  = read_wram_u8(HEART_TANKS_OFF)
  snap.upgrades     = read_wram_u8(UPGRADES_OFF)
  snap.shoryuken    = read_wram_u8(SHORYUKEN_OFF)
  snap.sigma_access = read_wram_u8(SIGMA_ACCESS_OFF)
  -- pickupsanity gate lives in CARTROM (per-seed-baked settings byte).
  snap.pickupsanity = (read_cartrom_u8(PICKUPSANITY_OFF) or 0) ~= 0
end

-- Live AP-validation word == 0xDEAD (game_watcher's per-frame gate).
local function validation_ok()
  return snap.validation ~= nil and snap.validation == VALIDATION_OK
end

-- ── One location's "checked?" test (mirrors game_watcher per internal_id) ─────
local function location_checked(internal_id, data_bit)
  if internal_id == T_BOSS then
    local v = snap.bosses[data_bit]                 -- defeated_bosses[data_bit] != 0
    return v ~= nil and v ~= 0
  elseif internal_id == T_MAVERICK then
    local v = snap.cleared[data_bit]                -- cleared_levels[data_bit] != 0
    return v ~= nil and v ~= 0
  elseif internal_id == T_HEART_TANK then
    local v = snap.heart_tanks                      -- heart_tanks & data_bit
    return v ~= nil and bit_and(v, data_bit) ~= 0
  elseif internal_id == T_UPGRADE or internal_id == T_SUB_TANK then
    local v = snap.upgrades                          -- upgrades & data_bit
    return v ~= nil and bit_and(v, data_bit) ~= 0
  elseif internal_id == T_SHORYUKEN then
    local v = snap.shoryuken                         -- shoryuken != 0
    return v ~= nil and v ~= 0
  elseif internal_id == T_SIGMA then
    local v = snap.sigma_access                      -- sigma_access != 0
    return v ~= nil and v ~= 0
  elseif internal_id == T_INTRO then
    -- game_state==0x02 AND menu_state==0x00 AND gameplay_state==0x01
    return snap.game_state == 0x02
       and snap.menu_state == 0x00
       and snap.gameplay_state == 0x01
  elseif internal_id == T_PICKUP then
    if not snap.pickupsanity then return false end
    local v = snap.pickups[data_bit]                 -- collected_pickups[data_bit] != 0
    return v ~= nil and v ~= 0
  end
  return false
end

-- ── Detection gate ────────────────────────────────────────────────────────────
-- game_watcher bails when game_state (game_state_data[0]) == 0 (title/no save)
-- and reports checks while game_state != 0. We also require the live 0xDEAD
-- validation word so a non-AP / un-booted ROM never reports.
local function in_gameplay()
  if not validation_ok() then return false end
  return snap.game_state ~= nil and snap.game_state ~= 0
end

-- ── Module contract ───────────────────────────────────────────────────────────
function M.init(ctx)
  if ctx and type(ctx.log) == "function" then log_fn = ctx.log end
  if not resolve_memory_api() then
    log("BizHawk memory API unavailable — module idle")
    ADDRESSES_VERIFIED = false
    return
  end
  local cfg = (ctx and ctx.config) or {}
  load_locations(cfg.locations)
  local n = 0; for _ in pairs(LOC) do n = n + 1 end
  log("ready: " .. n .. " location flags (items_handling=0b111; receive_item is a "
      .. "documented no-op pending in-emulator verification)")
end

function M.poll()
  local new = {}
  if not ADDRESSES_VERIFIED then return new end
  if not rom_is_ap() then return new end
  refresh_snapshot()
  if not in_gameplay() then return new end
  for ap_id, ld in pairs(LOC) do
    if not reported[ap_id] and wanted(ap_id) and location_checked(ld[1], ld[2]) then
      reported[ap_id] = true
      new[#new + 1] = ap_id
    end
  end
  return new
end

function M.is_goal_complete()
  if not ADDRESSES_VERIFIED or not rom_is_ap() then return false end
  refresh_snapshot()
  if not validation_ok() then return false end
  -- Sigma defeated: defeated_bosses[0x17] != 0 (the "Defeated Sigma" victory loc).
  local v = snap.bosses[GOAL_BOSS_INDEX]
  return v ~= nil and v ~= 0
end

-- Remote multiworld items: see the file header. items_handling = 0b111 means the
-- mmx2 client owns ALL item delivery — there is no game-self-grant fallback. The
-- delivery path is an intricate, heavily-state-gated set of WRAM writes (weapon/
-- upgrade/tank/enhancement/boss-access arrays + a recv-index handshake + arsenal
-- save/load + EnergyLink/DeathLink/HP-trade). It is the one piece deferred until
-- it can be confirmed in-emulator. No-op (never a wrong write) until then; checks
-- + goal above are fully functional regardless.
function M.receive_item(item_id, meta)
  -- intentionally empty (documented)
end

return M
